#include <stdio.h>
#include <stdint.h>
#define MOD 1000000007

uint64_t powmod(uint64_t base, uint64_t exponent, uint64_t mod) {
    uint64_t result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % mod;
        }
        exponent /= 2;
        base = (base * base) % mod;
    }
    return result;
}

uint64_t fibonacci(uint64_t n) {
    if (n <= 1) {
        return n;
    }
    uint64_t a = 0;
    uint64_t b = 1;
    for (uint64_t i = 2; i <= n; i++) {
        uint64_t temp = (a + b) % MOD;
        a = b;
        b = temp;
    }
    return b;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        uint64_t n;
        scanf("%llu", &n);
        if (n <= 2) {
            printf("%llu\n", n);
        } else {
            uint64_t result = (fibonacci(n + 2) - 1 + MOD) % MOD;
            printf("%llu\n", result);
        }
    }
    return 0;
}

