const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let t;
let i = 0;
let inputs = [];
rl.on('line', (line) => {
    if (i === 0) {
        t = parseInt(line);
    } else {
        inputs.push(parseInt(line));
    }
    i++;
    if (i === t + 1) {
        rl.close();
    }
});
rl.on('close', () => {
    for (let j = 0; j < t; j++) {
        let n = inputs[j];
